-- Enrichment marathon batch: Topaz Labs, Totango, TouchBistro, Tox, Traccar, TrackWatch, Tradogram, Traefik Hub

-- ── Topaz Labs ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Topaz Labs makes AI-powered photo and video enhancement software, including Topaz Photo AI, Topaz Video AI, and Topaz Gigapixel AI, used to upscale, sharpen, and denoise images and footage.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$From $19/month (individual app, billed annually)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Dallas, Texas, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Topaz Labs Review: AI Photo and Video Enhancement Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Topaz Labs builds AI tools like Photo AI, Video AI, and Gigapixel AI for upscaling, denoising, and sharpening images and video. See pricing, features, and pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Topaz Labs is a Dallas, Texas-based software company founded in 2005 by Dr. Feng (Albert) Yang, originally as a Photoshop plugin developer before pivoting to standalone AI-powered image and video enhancement tools. Its core desktop products are Topaz Photo AI (noise reduction, sharpening, and face recovery for still images), Topaz Video AI (frame interpolation, upscaling, and stabilization for footage), and Topaz Gigapixel AI (extreme image enlargement using neural networks). The company also offers cloud-based tools, Bloom for creative image upscaling and Astra for creative video upscaling, which run on Topaz servers rather than local hardware. Topaz says its software is trusted by more than one million photographers and filmmakers, including teams at organizations like Apple, Netflix, and NASA. In September 2025 Topaz shifted from a perpetual-license model to subscription-only pricing across its desktop apps, a change that drew criticism from long-time users accustomed to one-time purchases. Individual desktop apps now start around $19 to $39 per month depending on billing cycle and tier, while bundled plans such as Topaz Studio (all apps, unlimited local rendering, monthly cloud video credits) run from roughly $45 to $69 per month, and a Studio Pro tier adds higher export limits and full commercial-use rights. Cloud products like Astra, Bloom, and Mosaic are priced separately, often with usage-based credit systems for video rendering. Topaz differentiates itself from generic AI upscalers by offering deep, purpose-built models for photography and cinema-grade video work, plus plugin integration with Adobe Lightroom, Photoshop, and Premiere Pro, and DaVinci Resolve. Its main competitors include other AI upscaling and restoration tools as well as built-in AI features increasingly appearing in Adobe's own Creative Cloud apps.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8fd33ff2-2e47-4614-b590-5278d86d8871';

