-- ── Totango ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Totango is a customer success and customer intelligence platform that helps SaaS companies track account health, automate renewal and expansion playbooks, and reduce churn.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$~164 employees$q$, company_size),
  headquarters = COALESCE($q$Redwood City, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Totango Review: Customer Success and Retention Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Totango helps SaaS teams track customer health, automate playbooks, and reduce churn. See pricing tiers, key features, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Totango is a customer success software platform founded in 2010 and headquartered in Redwood City, California, with additional operations in New York and Tel Aviv. The company has raised roughly $148 million across multiple funding rounds, including a $100 million growth investment in 2021, from investors such as Great Hill Partners and ServiceNow Ventures. In February 2024, Totango merged with Catalyst Software, another customer success platform, and now operates three related products: Totango (the core customer success platform for health scoring, playbooks, and reporting), Unison (an AI-driven customer intelligence engine for churn-risk detection), and Catalyst (a customer growth platform focused on expansion and renewal signals). Totango's core platform lets customer success and revenue teams build automated journeys and playbooks triggered by account health signals, segment customers by tier or lifecycle stage, and integrate bidirectionally with CRMs like Salesforce and HubSpot. Unison adds AI-based risk-detection models, with both standard and custom model options, to flag accounts at risk of churn before renewal. Pricing for all three products is not published; Totango uses a custom, quote-based model tied to the number of practitioner seats, customer accounts tracked, and add-on services like a dedicated Enterprise Customer Success Manager. Publicly listed tiers include an Enterprise package (around 10 practitioner seats and 2,000 customer accounts) and a Premier package (around 20 practitioner seats and 10,000 customer accounts with a dedicated account team), both requiring a sales conversation for final pricing. Totango is typically compared to customer success platforms like Gainsight, ChurnZero, and Vitally, competing primarily on its long track record in the space and its combination of health scoring, AI-based risk detection, and growth-focused playbooks in one merged company.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '42178daa-c8ed-41d0-b8b7-d8e53057a2ce';

