-- ── Tox ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tox is a free, open-source peer-to-peer messaging and video-calling protocol built for end-to-end encrypted communication without central servers, developed by a volunteer community since 2013.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tox: Open Source Peer-to-Peer Encrypted Messaging Protocol$q$, seo_title),
  seo_meta_description = COALESCE($q$Tox is a free, decentralized, end-to-end encrypted messaging and video-call protocol with no central servers. See how it works and which clients support it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tox is a free, open-source instant-messaging and video-calling protocol focused on end-to-end encrypted, fully peer-to-peer communication, referenced under the domain tox.chat. It is a protocol and set of libraries, not a single company product, maintained by a volunteer, community-driven project rather than a commercial vendor. The idea originated on the anonymous imageboard 4chan in mid-2013, in the wake of Edward Snowden's NSA surveillance disclosures and concerns that Skype (recently acquired by Microsoft) had provided government access to its infrastructure. A group of developers around the world formed to build a library implementing the protocol; the first commit was pushed to GitHub on June 23, 2013 by a contributor using the handle irungentoo, and the project reached a public alpha stage on July 12, 2014. Tox uses NaCl-based cryptography (the same cryptographic library family used by libsodium) to encrypt all communication by default, with no option to disable encryption, and relies on a distributed hash table for peer discovery instead of centralized servers, meaning there is no company-run backend that stores messages or metadata. Since the core protocol is not an end-user app, various independent client applications implement it, including qTox, Toxic, uTox, and Antox, each offering somewhat different interfaces and platform support across Windows, macOS, Linux, and Android. Tox is entirely free with no subscription, account fee, or company behind it, which distinguishes it from centralized end-to-end encrypted messengers like Signal or WhatsApp that still route traffic through operator-controlled servers. Its main audience is privacy-focused users, developers, and activists seeking serverless communication resistant to centralized surveillance or takedown, though its smaller user base and inconsistent client maintenance over the years have kept it a niche tool compared to mainstream messaging apps.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '86a4e6f7-b835-4bf1-b393-2519995d609a';

