-- ── TrackWatch ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TrackWatch is a free, open-source, self-hosted tool that automatically tracks new releases from followed Spotify artists and syncs them into a dedicated playlist, keeping listening data on your own infrastructure.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$TrackWatch: Self-Hosted Spotify New Release Tracker$q$, seo_title),
  seo_meta_description = COALESCE($q$TrackWatch is a free, open-source, self-hosted app that auto-syncs new music releases from followed Spotify artists into a playlist.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TrackWatch is a free, open-source, self-hosted application that automatically tracks new music releases from a user's followed Spotify artists and syncs them into a dedicated playlist. It is created and maintained by developer emlopezr (Eduardo Lopez) and distributed under the MIT License through a public GitHub repository, rather than being backed by a company. The project is designed for privacy-conscious Spotify users: because it is self-hosted, typically via Docker, a user's Spotify OAuth tokens and listening data stay on their own infrastructure rather than being sent to a third-party service. Once configured, TrackWatch checks for new releases from followed artists on a fixed schedule, three times daily (7am, 2pm, and 9pm), and automatically adds any new songs, albums, or EPs to the user's playlist without manual intervention. Beyond basic release tracking, TrackWatch includes two power-user utilities: a discography generator that can build a complete playlist of every track from a given artist by searching for them, and a ghost track cleaner that detects and removes tracks that have since become unavailable on Spotify, keeping playlists tidy over time. Technically, the project uses a React 18, TypeScript, and Vite frontend built with React Router 7, paired with a Django 5 and Django REST Framework backend using APScheduler for scheduled jobs, Gunicorn as the application server, and PostgreSQL 15 as its database, all deployable together via Docker and Nginx. As a solo-developer open-source project, TrackWatch has no formal company, headquarters, or public founding date beyond its GitHub commit history, and there is no hosted or managed version offered, meaning users must be comfortable deploying and maintaining their own instance to use it.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '27408a9d-fa62-429f-be90-8c7e77ed1deb';

