-- ── Tradogram ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tradogram is a cloud-based procurement and spend management platform that helps businesses manage purchase orders, sourcing, supplier relationships, invoicing, and budgets from one place.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (1 user); Pro from $225/month billed annually$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Ottawa, Ontario, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tradogram Review: Procurement and Spend Management Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Tradogram is a cloud procurement platform for purchase orders, sourcing, suppliers, and invoicing. See pricing plans, features, and pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tradogram is a cloud-based procurement and spend management platform founded in 2009 and headquartered in Ottawa, Ontario, Canada. The company was co-founded by Hani Abdou (Founder and CEO) and Majdi Sleimen (Co-Founder and COO), and today employs roughly 11 to 50 people. The platform covers the full procure-to-pay cycle for businesses, including purchase order management, RFx sourcing events, supplier management, accounts payable invoice matching with OCR, budget tracking, contract management, and inventory management, aimed at helping purchasing teams control spend and automate manual procurement workflows. Tradogram uses a freemium pricing model, which is relatively unusual in the procurement software category where most competitors are quote-only. Its Free plan supports a single user with up to five transactions per month and limited items and suppliers, giving very small businesses or those evaluating the platform a genuine no-cost entry point with no time limit on the account. Paid tiers scale up from there: the Pro plan is priced at $225 per month billed annually with a one-user minimum and unlimited transactions, items, and suppliers, plus the full procurement toolset including custom approvals, report builder, and mobile apps; the Premium plan is $425 per month billed annually with a 10-user minimum, adding priority support and support for multiple companies or locations; and an Enterprise plan with a 20-user minimum offers custom pricing, a dedicated account manager, custom integrations, and options for private cloud or on-premise hosting. Tradogram is typically compared to other mid-market procurement platforms such as Procurify, Precoro, and Coupa, competing primarily on its combination of a genuinely free entry tier and a modular, all-in-one feature set that spans sourcing through invoicing rather than requiring separate point solutions.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3f5fd302-9cde-4c0c-9ce1-23c0223b163f';

