INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Supplier management$q$, $q$Track supplier relationships, performance, and contact information in one place.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$AP invoice matching with OCR$q$, $q$Automatically match incoming invoices against purchase orders and receipts using OCR.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Budget tracking$q$, $q$Monitor spend against allocated budgets across departments or projects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Contract management$q$, $q$Store and track supplier contracts alongside related purchase orders.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Inventory management$q$, $q$Track stock levels and link inventory data to procurement workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Custom approval workflows$q$, $q$Configure multi-step approval rules for purchase requisitions and orders.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Genuinely free tier for a single user, unusual among procurement software vendors$q$, 0);
