INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Broad feature set covering the full procure-to-pay cycle in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$White-labeling and mobile apps available on paid tiers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Long-running company in the procurement space since 2009$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Pro and Premium plans have relatively high monthly minimums for small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Premium plan requires a 10-user minimum regardless of actual team size$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Custom integrations and advanced deployment options are reserved for the Enterprise tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Pricing structure with per-plan user minimums can be confusing to compare against competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$What is Tradogram$q$, $q$Tradogram is a cloud-based procurement and spend management platform covering purchase orders, sourcing, supplier management, invoicing, and budgets.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Is Tradogram free$q$, $q$Tradogram offers a free Basic plan for a single user with up to five transactions per month; larger teams need a paid Pro, Premium, or Enterprise plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$How much does Tradogram cost$q$, $q$Tradogram's Pro plan starts at $225 per month billed annually, Premium is $425 per month billed annually with a 10-user minimum, and Enterprise pricing is custom for teams of 20 or more users.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$What is included in the free plan$q$, $q$The free plan includes one user, up to five transactions per month, and limited items and suppliers, with core purchase order management, receiving tracking, and AP invoice matching.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Does Tradogram support purchase order automation$q$, $q$Yes, Tradogram supports custom approval workflows and automated purchase order processes as part of its Pro plan and above.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Can Tradogram integrate with accounting software$q$, $q$Tradogram supports integration options, with custom integrations available on higher-tier and Enterprise plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Who founded Tradogram$q$, $q$Tradogram was founded in 2009 by Hani Abdou and Majdi Sleimen and is headquartered in Ottawa, Canada.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Is Tradogram cloud-based$q$, $q$Yes, Tradogram is a cloud-based platform, though the Enterprise plan also offers private cloud and on-premise deployment options.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Small business purchase order tracking$q$, $q$Small businesses use Tradogram's free plan to formalize purchase order tracking without upfront cost.$q$, $q$Small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Mid-size procurement sourcing$q$, $q$Mid-size procurement teams use Tradogram's RFx tools to run competitive sourcing events with suppliers.$q$, $q$Procurement and purchasing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Enterprise multi-branch procurement$q$, $q$Larger organizations use Tradogram's Enterprise plan for white-labeled, multi-branch procurement with custom integrations.$q$, $q$Enterprise operations and finance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Free (Basic)$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["One user only","Five transactions per month","Limited items and suppliers","Purchase order management","Receiving tracking","AP invoice matching","No time limit on account"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Pro$q$, $q$$225/month$q$, $q$Billed annually$q$, NULL, $q$["One user minimum","Unlimited transactions, items, and suppliers","Sourcing RFx and requisitions","AP invoices with OCR","Contract and inventory management","Custom approvals and report builder","Mobile apps"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Premium$q$, $q$$425/month$q$, $q$Billed annually$q$, NULL, $q$["10 user minimum","All Pro features included","Priority support","Multiple companies or locations","Custom white-label options"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$Enterprise$q$, $q$Custom quote$q$, $q$Contact sales$q$, NULL, $q$["20 user minimum","Assigned account manager","Unlimited users","Custom integrations and features","Multi-region hosting","Private cloud and on-premise options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$overview$q$, $q$What Is Tradogram$q$, 2, ARRAY[$q$Tradogram is a cloud-based procurement and spend management platform founded in 2009 and headquartered in Ottawa, Ontario, Canada. It was co-founded by Hani Abdou and Majdi Sleimen and is designed to give purchasing teams a single system for managing the full procure-to-pay process.$q$, $q$The platform covers purchase order creation and management, supplier relationship tracking, RFx sourcing events for competitive bidding, accounts payable invoice matching, budget tracking, contract management, and inventory management, positioning itself as an all-in-one alternative to stitching together multiple point solutions.$q$, $q$Tradogram is aimed primarily at small and mid-sized businesses that want structured procurement controls, such as approval workflows and spend visibility, without the implementation overhead and cost typically associated with large enterprise procurement suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core purchasing features include purchase order management with custom approval workflows, requisitions, and expense tracking, letting finance and procurement teams enforce spend controls before money leaves the business.$q$, $q$Sourcing and supplier features include RFx tools for running competitive sourcing events and a supplier management module for tracking vendor relationships and performance over time.$q$, $q$On the financial side, Tradogram offers AP invoice matching with OCR to reconcile invoices against purchase orders and receipts, budget tracking to monitor spend against allocated amounts, and a report builder for custom procurement analytics, alongside contract and inventory management modules for teams that need broader spend visibility.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3f5fd302-9cde-4c0c-9ce1-23c0223b163f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Tradogram offers a genuinely free Basic plan for a single user with up to five transactions per month, limited items and suppliers, and no time limit on the account, making it accessible for very small businesses or evaluation purposes.$q$, $q$Paid plans scale with team size and features: Pro is $225 per month billed annually with a one-user minimum and unlimited transactions and the full procurement toolset; Premium is $425 per month billed annually with a 10-user minimum and adds priority support and multi-company or multi-location support; and Enterprise, requiring a minimum of 20 users, is custom-priced and adds a dedicated account manager, custom integrations, and private cloud or on-premise deployment options.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$GitOps-compliant API publishing$q$, $q$Manage API configuration and publishing through version-controlled, declarative GitOps workflows.$q$, 0);
