INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Centralized rate limiting and quotas$q$, $q$Apply consistent usage limits across APIs from a central control plane.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Self-serve API portal$q$, $q$Lets API consumers discover, document, and test APIs, with usage and error analytics.$q$, 3);
