INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Built-in observability$q$, $q$Open standards-based observability and analytics across managed APIs.$q$, 6);
