INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Several capabilities are gated behind paid API Gateway or API Management tiers rather than the free Traefik Proxy$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$What is Traefik Hub$q$, $q$Traefik Hub is Traefik Labs' commercial, Kubernetes-native API management and API gateway product built on top of the open-source Traefik Proxy.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$How is Traefik Hub different from open-source Traefik$q$, $q$Open-source Traefik Proxy is a free reverse proxy, load balancer, and ingress controller, while Traefik Hub is a separate paid product that adds API management features like a developer portal, subscriptions, GitOps publishing, and advanced security controls.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Does Traefik Hub work with non-Traefik ingress controllers$q$, $q$Yes, Traefik Hub explicitly supports third-party ingress controllers, including NGINX, alongside Traefik's own ingress controller.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$How much does Traefik Hub cost$q$, $q$Traefik Labs does not publish pricing for Traefik Hub; both its API Gateway and API Management tiers require contacting sales for a custom quote.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Does Traefik Hub require Kubernetes$q$, $q$Traefik Hub is built specifically for Kubernetes-native environments, so most of its value assumes an existing Kubernetes-based infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Who makes Traefik Hub$q$, $q$Traefik Hub is made by Traefik Labs, the company founded in 2016 by Emile Vauge that also maintains the open-source Traefik Proxy project.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$What is Traefik Labs$q$, $q$Traefik Labs is the company behind the widely used open-source Traefik Proxy, as well as the commercial API Gateway and Traefik Hub API management products; it was originally founded as Containous in 2016.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Does Traefik Hub support GitOps workflows$q$, $q$Yes, Traefik Hub is designed to be fully GitOps-compliant, letting teams manage API publishing through version-controlled, declarative configuration.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Kubernetes API governance$q$, $q$Platform engineering teams use Traefik Hub to centrally manage and govern APIs across Kubernetes clusters.$q$, $q$Platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Self-serve developer portals$q$, $q$Companies use Traefik Hub's API portal to let internal or partner developers discover and test APIs without manual onboarding.$q$, $q$API platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Modernizing legacy API gateways$q$, $q$Organizations replace legacy, non-GitOps API gateways with Traefik Hub's GitOps-native approach.$q$, $q$DevOps and infrastructure teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$Application Proxy$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source Traefik Proxy","Ingress controller and reverse proxy","Auto-discovery and load balancing","Dashboard and metrics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$API Gateway$q$, $q$Custom quote$q$, $q$Contact sales$q$, NULL, $q$["Everything in Application Proxy","Web application firewall","Advanced authentication: LDAP, JWT, OAuth, OIDC","Rate limiting and caching","Multi-cluster management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$API Management$q$, $q$Custom quote$q$, $q$Contact sales$q$, NULL, $q$["Everything in API Gateway","API mocking and request validation","Centralized control plane","API discovery and versioning","Self-serve developer portal and subscriptions"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$overview$q$, $q$What Is Traefik Hub$q$, 2, ARRAY[$q$Traefik Hub is the commercial API management and API gateway product built by Traefik Labs, the company behind the widely used open-source Traefik Proxy. It is important to distinguish the two: Traefik Proxy is a free, open-source reverse proxy, load balancer, and Kubernetes ingress controller, while Traefik Hub is a separate, paid add-on focused specifically on managing, securing, and publishing APIs at scale.$q$, $q$Traefik Labs was founded in 2016 by Emile Vauge, originally under the name Containous, and grew out of Vauge's work building Traefik as a side project that attracted a large community of contributors. The company has since grown into a broader cloud-native networking and API management vendor built around that original open-source project.$q$, $q$Traefik Hub is designed to work in Kubernetes environments and is explicitly built to be GitOps-compliant, meaning API configuration and publishing decisions can be managed through the same version-controlled, declarative workflows that platform teams already use for infrastructure and application deployments.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Traefik Hub provides centralized rate limiting and quotas across APIs, along with subscription management tools that let organizations create managed or self-serve API subscriptions for internal teams or external partners.$q$, $q$A self-serve API portal is a core piece of the product, offering API discovery, documentation, and interactive testing along with error and usage analytics, so API consumers can find and start using an API without manual onboarding from a platform team.$q$, $q$Notably, Traefik Hub is not limited to organizations running Traefik's own ingress controller; it supports third-party ingress controllers including NGINX, positioning it as a Kubernetes-native API management layer that can sit on top of an organization's existing ingress setup rather than requiring a full migration to Traefik.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea6717b3-d173-4853-b8b4-beb2d3f1c1e0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Traefik Labs structures its product line into three tiers on its pricing page: Application Proxy, which is the free, open-source Traefik Proxy with core ingress and load balancing features; API Gateway, a paid tier adding a web application firewall, advanced authentication (LDAP, JWT, OAuth, OIDC), rate limiting, caching, and multi-cluster management; and API Management, the full Traefik Hub offering, which adds API mocking, request validation, a centralized control plane, API discovery and versioning, and the self-serve developer portal.$q$, $q$None of the paid tiers publish specific pricing; both API Gateway and API Management are marked for organizations to contact Traefik Labs sales to get a quote based on their cluster and usage requirements.$q$]::text[], 2);
